// Extract and structure form data with lead ID
const formData = $input.item.json;

return {
  json: {
    lead_id: `LEAD-${Date.now()}`,
    timestamp: new Date().toISOString(),
    company: formData.company,
    contact_name: formData.name,
    email: formData.email,
    phone: formData.phone || '',
    company_size: formData.size,
    current_software: formData.software || 'Not specified',
    pain_point: formData.pain || 'Not specified',
    wants_ai_audit: formData.ai_audit === true || formData.ai_audit === 'yes',
    source: formData.source || 'website',
    submitted_at: formData.submitted_at || new Date().toISOString()
  }
};

// Parse OpenRouter response and merge with lead data
const leadData = $input.first().json;
const openRouterResponse = $input.item.json;

// Extract AI message from OpenRouter format
let aiResponseRaw = openRouterResponse.choices[0].message.content;

// Clean response (remove markdown if present)
let cleanResponse = aiResponseRaw;
if (aiResponseRaw.includes('```json')) {
  cleanResponse = aiResponseRaw.split('```json')[1].split('```')[0].trim();
} else if (aiResponseRaw.includes('```')) {
  cleanResponse = aiResponseRaw.split('```')[1].trim();
}

let analysis;
try {
  analysis = JSON.parse(cleanResponse);
} catch (e) {
  console.error('AI response parsing failed:', e);
  analysis = {
    lead_score: "warm",
    score_reason: "Needs manual review - AI parsing failed",
    key_pain_points: [leadData.pain_point],
    recommended_services: ["AI Lead Response Systems"],
    estimated_monthly_value: "$5,000 - $15,000",
    urgency: "within_week",
    next_steps: ["Schedule assessment call", "Review current workflow", "Discuss pricing"]
  };
}

return {
  json: {
    ...leadData,
    analysis: analysis,
    lead_score: analysis.lead_score,
    score_reason: analysis.score_reason,
    estimated_value: analysis.estimated_monthly_value,
    urgency: analysis.urgency,
    next_steps: analysis.next_steps,
    recommended_services: analysis.recommended_services,
    key_pain_points: analysis.key_pain_points
  }
};

