// Parse detailed audit from OpenRouter and merge
const leadData = $input.first().json;
const openRouterResponse = $input.item.json;

// Extract AI message
let auditResponseRaw = openRouterResponse.choices[0].message.content;

// Clean response
let cleanResponse = auditResponseRaw;
if (auditResponseRaw.includes('```json')) {
  cleanResponse = auditResponseRaw.split('```json')[1].split('```')[0].trim();
} else if (auditResponseRaw.includes('```')) {
  cleanResponse = auditResponseRaw.split('```')[1].trim();
}

let detailedAudit;
try {
  detailedAudit = JSON.parse(cleanResponse);
} catch (e) {
  console.error('Audit parsing failed:', e);
  detailedAudit = {
    audit_summary: `Based on ${leadData.company}'s needs, we recommend focusing on workflow automation to address their primary pain point: ${leadData.pain_point}. Expected ROI within 6 months.`,
    roi_projections: {
      annual_time_savings_hours: 500,
      annual_cost_reduction: "$35,000",
      revenue_opportunity: "$50,000",
      total_annual_value: "$85,000",
      payback_period_months: 4
    },
    next_actions: [
      "Schedule 30-minute deep-dive call",
      "Review current workflow documentation",
      "Prepare ROI calculator for specific use case"
    ]
  };
}

return {
  json: {
    ...leadData,
    detailed_audit: detailedAudit,
    audit_summary: detailedAudit.audit_summary,
    roi_annual_value: detailedAudit.roi_projections?.total_annual_value || leadData.estimated_value
  }
};

